// Middleware that sets headers on a future Response (rate limiting + cookie)
// This uses the runtime-provided helper `setResponseHeaders` shown in Expo/Router docs.
export default function middleware(request: Request) {
  // Example: add a Retry-After header for downstream handlers
  setResponseHeaders({ 'Retry-After': '3600' });

  // Example: append a Set-Cookie header to the future Response
  // Use a callback to mutate headers (safer when middleware chains exist)
  setResponseHeaders((headers: Headers) => {
    headers.append('Set-Cookie', 'token=secure-token-123; Path=/; HttpOnly; Secure; Max-Age=3600');
  });

  // No Response returned here so the request continues to the route handler
}


