// API route that schedules a background analytics ping after the Response resolves
// This uses the runtime-provided helper `deferTask` shown in Expo/Router docs.
export async function GET(request: Request) {
  // Schedule work to run after this function resolves and the Response is sent
  deferTask(async () => {
    try {
      await fetch('https://example.com/analytics', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'api_called',
          path: new URL(request.url).pathname,
          timestamp: Date.now(),
        }),
      });
    } catch (err) {
      // Swallow errors in deferred tasks so they don't affect the main Response
      console.error('Deferred analytics failed:', err);
    }
  });

  // Normal synchronous-ish work for the route
  const res = await fetch('https://jsonplaceholder.typicode.com/todos/1');
  const data = await res.json();

  // Return using Response.json() as in the documented runtime
  return Response.json({ data });
}

import React, { useContext, useState, useCallback } from 'react';
import { View, Text, TextInput, Button, StyleSheet } from 'react-native';
import { RootTagContext, NativeNavigation, NativeAnalytics } from 'react-native';

const ScreenWithRootTag = () => {
  // Get the root tag from React Context using hooks
  const rootTag = useContext(RootTagContext);
  const [title, setTitle] = useState('');

  const updateTitle = useCallback(() => {
    // Set the native navigation title for this rootTag
    NativeNavigation.setTitle(rootTag, title || 'Default Title');
  }, [rootTag, title]);

  const handleOneEvent = useCallback(() => {
    // Log an analytics event scoped to this rootTag
    NativeAnalytics.logEvent(rootTag, 'one_event');
  }, [rootTag]);

  return (
    <View style={styles.container}>
      <Text style={styles.label}>RootTag: {String(rootTag)}</Text>
      <TextInput
        style={styles.input}
        value={title}
        onChangeText={setTitle}
        placeholder="Enter new title"
        accessibilityLabel="title-input"
      />
      <View style={styles.button}>
        <Button title="Update Title" onPress={updateTitle} />
      </View>
      <View style={styles.button}>
        <Button title="Log Analytics Event" onPress={handleOneEvent} />
      </View>
    </View>
  );
};

