import React, { createContext, useContext, useRef, useCallback, useState } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';

// Root stack types
type RootStackParamList = {
  Home: undefined;
  Details: { callbackId: string };
};

const Stack = createNativeStackNavigator<RootStackParamList>();

// Callback registry context
type CallbackContextType = {
  register: (cb: (data: any) => void) => string;
  invoke: (id: string, data?: any) => void;
  unregister: (id: string) => void;
};

const CallbackContext = createContext<CallbackContextType | undefined>(undefined);

const CallbackProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const mapRef = useRef<Map<string, (d?: any) => void>>(new Map());

  const register = useCallback((cb: (d?: any) => void) => {
    const id = `${Date.now()}_${Math.random().toString(36).slice(2)}`;
    mapRef.current.set(id, cb);
    return id;
  }, []);

  const invoke = useCallback((id: string, data?: any) => {
    const cb = mapRef.current.get(id);
    if (cb) {
      cb(data);
      mapRef.current.delete(id); // auto-cleanup after invoking
    }
  }, []);

  const unregister = useCallback((id: string) => {
    mapRef.current.delete(id);
  }, []);

  return (
    <CallbackContext.Provider value={{ register, invoke, unregister }}>
      {children}
    </CallbackContext.Provider>
  );
};

function useCallbackRegistry(): CallbackContextType {
  const ctx = useContext(CallbackContext);
  if (!ctx) throw new Error('useCallbackRegistry must be used within CallbackProvider');
  return ctx;
}

// Home screen: register a callback and navigate passing only a callbackId (serializable)
const HomeScreen: React.FC<any> = ({ navigation }) => {
  const [message, setMessage] = useState<string>('No result yet');
  const { register, unregister } = useCallbackRegistry();

  const openDetails = () => {
    const id = register((data?: any) => {
      setMessage(typeof data === 'string' ? data : JSON.stringify(data));
    });

    // Pass only the id (string) in params — serializable
    navigation.navigate('Details', { callbackId: id });

    // Optional: unregister after some timeout if you expect no response
    // setTimeout(() => unregister(id), 30_000);
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Home</Text>
      <Text style={styles.message}>{message}</Text>
      <Button title="Open Details" onPress={openDetails} />
    </View>
  );
};

// Details screen: read callbackId param and invoke the registered callback via context
const DetailsScreen: React.FC<any> = ({ route, navigation }) => {
  const { callbackId } = route.params as { callbackId: string };
  const { invoke } = useCallbackRegistry();

  const sendResultAndGoBack = () => {
    // Invoke the callback stored in the registry using the id we received
    invoke(callbackId, 'Hello from Details screen!');
    navigation.goBack();
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Details</Text>
      <Text style={styles.message}>Callback ID: {callbackId}</Text>
      <Button title="Send Result and Go Back" onPress={sendResultAndGoBack} />
    </View>
  );
};

export default function App() {
  return (
    <CallbackProvider>
      <NavigationContainer>
        <Stack.Navigator>
          <Stack.Screen name="Home" component={HomeScreen} />
          <Stack.Screen name="Details" component={DetailsScreen} />
        </Stack.Navigator>
      </NavigationContainer>
    </CallbackProvider>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, alignItems: 'center', justifyContent: 'center', padding: 16 },
  title: { fontSize: 24, marginBottom: 12 },
  message: { fontSize: 16, marginBottom: 20, textAlign: 'center' },
});

