import { setResponseHeaders } from 'expo/server';

// Middleware that attaches headers to the future Response created by an API route
export default function middleware(request: Request) {
  setResponseHeaders(headers => {
    // Add a Retry-After header for rate limiting
    headers.set('Retry-After', '3600');
    // Append a cookie (example: session/token) safely
    headers.append('Set-Cookie', 'token=123; Secure; HttpOnly; SameSite=Strict');
    return headers;
  });

  // No Response returned here; middleware only mutates headers for the eventual route Response
}

