import { deferTask } from 'expo/server';

// Example GET API route that returns JSON immediately and defers an analytics ping
export async function GET(request: Request) {
  // Schedule a background task that runs after this Response is resolved
  deferTask(async () => {
    try {
      await pingAnalytics(request);
    } catch (err) {
      // Log but do not block the response
      // Runtime will handle errors for deferred tasks as appropriate
      console.error('Deferred analytics ping failed', err);
    }
  });

  const data = await fetchExampleData();

  return new Response(JSON.stringify({ data }), {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}

// --- Helpers ---
async function fetchExampleData() {
  // Replace with real data fetching logic
  const res = await fetch('https://jsonplaceholder.typicode.com/todos/1');
  if (!res.ok) throw new Error('Failed to fetch example data');
  return await res.json();
}

async function pingAnalytics(request: Request) {
  // Minimal, non-blocking analytics payload
  const url = new URL(request.url);
  await fetch('https://example-analytics.local/ping', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      path: url.pathname,
      ts: new Date().toISOString(),
    }),
  });
}
